/* ══════════════════════════════════════
   AUDIO (Web Audio API)
══════════════════════════════════════ */
let _aCtx=null;
function getAudio(){if(!_aCtx)_aCtx=new(window.AudioContext||window.webkitAudioContext)();return _aCtx;}
function playTone(f,d,t='sine',v=0.3,dl=0){try{const a=getAudio(),o=a.createOscillator(),g=a.createGain();o.connect(g);g.connect(a.destination);o.type=t;o.frequency.setValueAtTime(f,a.currentTime+dl);g.gain.setValueAtTime(0,a.currentTime+dl);g.gain.linearRampToValueAtTime(v,a.currentTime+dl+.01);g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dl+d);o.start(a.currentTime+dl);o.stop(a.currentTime+dl+d+.05);}catch(e){}}
function playNoise(d,v=0.15,dl=0){try{const a=getAudio(),buf=a.createBuffer(1,a.sampleRate*d,a.sampleRate),dt=buf.getChannelData(0);for(let i=0;i<dt.length;i++)dt[i]=(Math.random()*2-1);const src=a.createBufferSource(),g=a.createGain(),f=a.createBiquadFilter();f.type='bandpass';f.frequency.value=800;f.Q.value=0.5;src.buffer=buf;src.connect(f);f.connect(g);g.connect(a.destination);g.gain.setValueAtTime(v,a.currentTime+dl);g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dl+d);src.start(a.currentTime+dl);src.stop(a.currentTime+dl+d+.05);}catch(e){}}
function sndFlight(big){
  try{
    const a=getAudio(),dur=big?.65:.85;
    // 흰 노이즈 → bandpass 스윕으로 쉬익~ 바람 소리
    const len=Math.ceil(a.sampleRate*(dur+.1));
    const buf=a.createBuffer(1,len,a.sampleRate),dt=buf.getChannelData(0);
    // 페이드인→페이드아웃 envelope
    for(let i=0;i<len;i++){
      const env=Math.sin(i/len*Math.PI); // 0→1→0 자연스러운 곡선
      dt[i]=(Math.random()*2-1)*env;
    }
    const src=a.createBufferSource();
    src.buffer=buf;
    // bandpass: 중간 주파수만 통과 → 쉬익 바람 질감
    const bp=a.createBiquadFilter();
    bp.type='bandpass';
    bp.frequency.setValueAtTime(big?2200:1800,a.currentTime);
    bp.frequency.exponentialRampToValueAtTime(big?800:600,a.currentTime+dur);
    bp.Q.value=1.8;
    // 볼륨
    const g=a.createGain();
    g.gain.setValueAtTime(.001,a.currentTime);
    g.gain.linearRampToValueAtTime(.18,a.currentTime+dur*.2);
    g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dur);
    src.connect(bp);bp.connect(g);g.connect(a.destination);
    src.start(a.currentTime);src.stop(a.currentTime+dur+.1);
  }catch(e){}
}
function sndEnemyFlight(){
  try{
    const a=getAudio();
    // 적 포탄: 위협적인 낮은 바람 — 쿵 하고 날아오는 느낌
    const dur=.75;
    const len=Math.ceil(a.sampleRate*(dur+.1));
    const buf=a.createBuffer(1,len,a.sampleRate),dt=buf.getChannelData(0);
    for(let i=0;i<len;i++){
      const env=Math.pow(Math.sin(i/len*Math.PI),0.6);
      dt[i]=(Math.random()*2-1)*env;
    }
    const src=a.createBufferSource(),g=a.createGain();
    const bp=a.createBiquadFilter();bp.type='bandpass';
    // 저음 → 더 저음: 다가오는 위협감
    bp.frequency.setValueAtTime(600,a.currentTime);
    bp.frequency.exponentialRampToValueAtTime(180,a.currentTime+dur);
    bp.Q.value=1.4;
    src.buffer=buf;src.connect(bp);bp.connect(g);g.connect(a.destination);
    g.gain.setValueAtTime(.001,a.currentTime);
    g.gain.linearRampToValueAtTime(.22,a.currentTime+dur*.3);
    g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dur);
    src.start();src.stop(a.currentTime+dur+.1);
  }catch(e){}
}
function sndCannon(){
  try{
    const a=getAudio();
    // 낮고 둔탁한 발사음 — 포구의 화약 폭발
    const len=Math.ceil(a.sampleRate*.08);
    const buf=a.createBuffer(1,len,a.sampleRate),dt=buf.getChannelData(0);
    for(let i=0;i<len;i++)dt[i]=(Math.random()*2-1)*Math.pow(1-i/len,1.2);
    const src=a.createBufferSource(),g=a.createGain();
    const lp=a.createBiquadFilter();lp.type='lowpass';lp.frequency.value=320;
    src.buffer=buf;src.connect(lp);lp.connect(g);g.connect(a.destination);
    g.gain.setValueAtTime(.7,a.currentTime);
    g.gain.exponentialRampToValueAtTime(.001,a.currentTime+.22);
    src.start();
    // 저음 쿵
    const o=a.createOscillator(),og=a.createGain();
    o.connect(og);og.connect(a.destination);o.type='sine';
    o.frequency.setValueAtTime(80,a.currentTime);
    o.frequency.exponentialRampToValueAtTime(28,a.currentTime+.35);
    og.gain.setValueAtTime(.55,a.currentTime);
    og.gain.exponentialRampToValueAtTime(.001,a.currentTime+.38);
    o.start();o.stop(a.currentTime+.42);
  }catch(e){}
}
function sndExplode(big){
  const a=getAudio();
  function sw(f1,f2,d,t,v,dl=0){const o=a.createOscillator(),g=a.createGain();o.connect(g);g.connect(a.destination);o.type=t;o.frequency.setValueAtTime(f1,a.currentTime+dl);o.frequency.exponentialRampToValueAtTime(f2,a.currentTime+dl+d);g.gain.setValueAtTime(v,a.currentTime+dl);g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dl+d);o.start(a.currentTime+dl);o.stop(a.currentTime+dl+d+.06);}
  const s=big?1.0:.7;
  playNoise(.06,.65*s,0);playNoise(.8,.55*s,0,.04);sw(80,25,.9,'sine',.62*s,.03);playNoise(.6,.4*s,0,.2);
}
function sndCorrect(){}
function sndWrong(){}
function sndCombo(lv){
  if(lv>=15){
    // 학익진: 화려한 팡파레
    playTone(880,.15,'sine',.42);playTone(1100,.15,'sine',.4,.15);playTone(1320,.26,'sine',.48,.3);
    playNoise(.3,.3,.05);playNoise(.25,.25,.2);
  } else if(lv>=10){
    // 거북선: 0.2초 충전음 후 묵직한 대포
    playTone(120,.18,'sawtooth',.18);// 저음 웅웅
    playTone(90,.15,'sine',.22,.05);
    setTimeout(()=>{playNoise(.6,.55);playTone(55,.55,'sawtooth',.38);playTone(75,.45,'sine',.25);},220);
  } else if(lv>=5){
    // 연속 포격: 탕탕 총소리 2발
    function gunShot(){
      // C-7 전열함 일제사격 — 3발 묵직하게
      try{
        const a=getAudio();
        function sw(f1,f2,d,t,v,dl){const o=a.createOscillator(),g=a.createGain();o.connect(g);g.connect(a.destination);o.type=t;o.frequency.setValueAtTime(f1,a.currentTime+dl);o.frequency.exponentialRampToValueAtTime(f2,a.currentTime+dl+d);g.gain.setValueAtTime(v,a.currentTime+dl);g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dl+d);o.start(a.currentTime+dl);o.stop(a.currentTime+dl+d+.06);}
        function shot(dl,i){
          const len=Math.ceil(a.sampleRate*.1);
          const buf=a.createBuffer(1,len,a.sampleRate),dt=buf.getChannelData(0);
          for(let j=0;j<len;j++)dt[j]=(Math.random()*2-1)*Math.pow(1-j/len,1.5);
          const src=a.createBufferSource(),g=a.createGain(),lp=a.createBiquadFilter();
          lp.type='lowpass';lp.frequency.value=500;
          src.buffer=buf;src.connect(lp);lp.connect(g);g.connect(a.destination);
          g.gain.setValueAtTime(.45,a.currentTime+dl);
          g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dl+.08);
          src.start(a.currentTime+dl);
          sw(70-i*5,30,.4,'sine',.48,dl);
        }
        shot(0,0);shot(.1,1);shot(.2,2);
      }catch(e){}
    }
    gunShot();
    setTimeout(gunShot, 200);
  }
}
function sndEnemyAtk(){
  const a=getAudio();
  function sw(f1,f2,d,t,v,dl=0){const o=a.createOscillator(),g=a.createGain();o.connect(g);g.connect(a.destination);o.type=t;o.frequency.setValueAtTime(f1,a.currentTime+dl);o.frequency.exponentialRampToValueAtTime(f2,a.currentTime+dl+d);g.gain.setValueAtTime(v,a.currentTime+dl);g.gain.exponentialRampToValueAtTime(.001,a.currentTime+dl+d);o.start(a.currentTime+dl);o.stop(a.currentTime+dl+d+.06);}
  // A-2 칼 휘두르기 — 쒜엑
  playNoise(.2,.38,0);sw(500,200,.16,'sawtooth',.28);playNoise(.14,.25,.12);
}
function sndVictory(){[523,659,784,1047].forEach((f,i)=>playTone(f,.3,'sine',.36,i*.18));}
function sndClick(){try{
  const a=getAudio();
  [[1000,.008,'square',.08,0],[400,.04,'sine',.05,.008]].forEach(function(p){
    const o=a.createOscillator(),g=a.createGain();
    o.connect(g);g.connect(a.destination);
    o.type=p[2];o.frequency.value=p[0];
    g.gain.setValueAtTime(p[3],a.currentTime+p[4]);
    g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+p[4]+p[1]);
    o.start(a.currentTime+p[4]);o.stop(a.currentTime+p[4]+p[1]+.01);
  });
}catch(e){}}

// 카드 도감 전용: 기본 클릭음보다 살짝 더 존재감 있는 '스윽' 플립 효과음
function sndCardFlip(){try{
  const a=getAudio();
  const len=Math.ceil(a.sampleRate*0.16);
  const buf=a.createBuffer(1,len,a.sampleRate),dt=buf.getChannelData(0);
  // 화이트노이즈 + 부드러운 감쇠 → 스윽
  for(let i=0;i<len;i++){
    const t=i/len;
    const env=Math.pow(1-t,2.0);
    dt[i]=(Math.random()*2-1)*0.42*env;
  }
  const src=a.createBufferSource(),g=a.createGain(),bp=a.createBiquadFilter();
  bp.type='bandpass';
  bp.frequency.value=1100; // 중역대 쪽으로 조금 내려서 거슬리지 않게
  bp.Q.value=2.2;
  src.buffer=buf;
  src.connect(bp);bp.connect(g);g.connect(a.destination);
  g.gain.setValueAtTime(0.42,a.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.16);
  src.start();src.stop(a.currentTime+0.18);
}catch(e){}}

/* ══════════════════════════════════════
   FX CANVAS
══════════════════════════════════════ */
const fxC=document.getElementById('fxCanvas'),fxX=fxC.getContext('2d');
function resizeFx(){const p=document.getElementById('battleBgPanel');if(p){fxC.width=p.offsetWidth;fxC.height=p.offsetHeight;}}
window.addEventListener('resize',resizeFx);
let particles=[];

function addP(x,y,vx,vy,r,c,l){particles.push({x,y,vx,vy,r,c,l,ml:l});}
(function tick(){
  fxX.clearRect(0,0,fxC.width,fxC.height);
  particles=particles.filter(p=>{p.x+=p.vx;p.y+=p.vy;p.vy+=.2;p.l--;fxX.globalAlpha=p.l/p.ml;fxX.fillStyle=p.c;fxX.beginPath();fxX.arc(p.x,p.y,p.r,0,Math.PI*2);fxX.fill();return p.l>0;});
  fxX.globalAlpha=1;requestAnimationFrame(tick);
})();

function spawnExplosion(x,y,big=false){
  const n=big?90:45;
  for(let i=0;i<n;i++){const a=Math.random()*Math.PI*2,s=(big?2.5:1.5)+Math.random()*(big?5:3);const cs=['#ff9500','#ffcc00','#ff4500','#fff','#ffdd44','#ff6b00'];addP(x,y,Math.cos(a)*s,Math.sin(a)*s-(big?3:2),(big?2.5:1.5)+Math.random()*(big?4:2.5),cs[~~(Math.random()*cs.length)],big?60:38);}
}

function spawnSmoke(x,y,n=10){for(let i=0;i<n;i++)addP(x+(Math.random()-.5)*16,y,(Math.random()-.5)*1.1,-1.2-Math.random()*1.8,4+Math.random()*7,`rgba(180,140,100,${.28+Math.random()*.35})`,36+~~(Math.random()*25));}

function spawnCannonSmoke(x,y){for(let i=0;i<18;i++)addP(x+(Math.random()-.5)*8,y+(Math.random()-.5)*8,2.5+Math.random()*2.5,(Math.random()-.5)*1.5,3+Math.random()*5,`rgba(220,200,150,${.45+Math.random()*.4})`,28+~~(Math.random()*18));}

// ==================== 1. 아군 공격 (정답 = 초록) ====================
function launchCannonball(sx, sy, tx, ty, big, isEnemy = false) {
  const stage = document.getElementById('battleBgPanel');
  if (isEnemy) { sndEnemyFlight(); } else { sndCannon(); sndFlight(big); }
  spawnCannonSmoke(sx, sy);

  const ball = document.createElement('div');
  const sz = big ? 14 : 10;
  const col = isEnemy
    ? 'radial-gradient(circle,#ff4444,#aa0000,#330000)'
    : 'radial-gradient(circle,#ffee44,#ff8800,#661100)';
  
  ball.style.cssText = `position:absolute;width:${sz}px;height:${sz}px;border-radius:50%;background:${col};box-shadow:0 0 ${big?14:8}px ${isEnemy?'rgba(255,50,50,.9)':'rgba(255,160,0,.9)'};pointer-events:none;z-index:10;`;
  ball.style.left = sx + 'px';
  ball.style.top = sy + 'px';
  stage.appendChild(ball);

  const df = document.getElementById('dmgFlash');

  // 빨강 기준으로 완전히 통일
  const dur = 950;
  const startT = performance.now();

  (function mv(now) {
    const t = Math.min((now - startT) / dur, 1);
    const x = sx + (tx - sx) * t;
    const y = (sy + (ty - sy) * t) - Math.sin(t * Math.PI) * (stage.offsetHeight * 0.15);  // 빨강과 동일한 arc

    ball.style.left = x + 'px';
    ball.style.top = y + 'px';

    if (t < 1) {
      requestAnimationFrame(mv);
    } else {
      ball.remove();
      spawnExplosion(tx, ty, big);
      spawnSmoke(tx, ty);
      sndExplode(big);

      // 플래시: 빨강과 100% 동일한 코드
        // ★★★★★ 최종 강제 초기화 버전 ★★★★★
      if (df) {
        // 모든 기존 스타일 강제로 지우기
        df.style.cssText = 'transition:none !important; background:transparent !important; box-shadow:none !important; opacity:0 !important;';

        // 아주 살짝 딜레이 후 플래시 시작 (이게 핵심!)
        setTimeout(() => {
          if (isEnemy) {
            // 틀렸을 때 (빨강) - 당신 기준
            df.style.cssText = 'background:rgba(231,76,60,.35) !important; box-shadow:0 0 90px rgba(231,76,60,0.9) !important; opacity:1 !important; transition:none !important;';
          } else {
            // 맞았을 때 (초록) - 빨강과 **강도 완전히 동일**
            df.style.cssText = 'background:rgba(46,204,113,.35) !important; box-shadow:0 0 90px rgba(46,204,113,0.9) !important; opacity:1 !important; transition:none !important;';
          }
        }, 5);

        // 380ms 후 사라지게
        setTimeout(() => {
          df.style.opacity = '0';
          setTimeout(() => {
            df.style.cssText = 'background:transparent !important; box-shadow:none !important;';
          }, 400);
        }, 380);
      }
    }
  })(performance.now());
}

// ==================== 2. 적군 공격 (오답 = 빨강) ====================
function launchEnemyBall(stage, sx, sy, tx, ty) {
  const ball = document.createElement('div');
  ball.style.cssText = `position:absolute;width:11px;height:11px;border-radius:50%;background:radial-gradient(circle,#ff6600,#cc2200,#440000);box-shadow:0 0 10px rgba(255,80,0,.9),0 0 4px rgba(255,200,0,.7);pointer-events:none;z-index:10;`;
  ball.style.left = sx + 'px';
  ball.style.top = sy + 'px';
  stage.appendChild(ball);

  const dur = 950, startT = performance.now();
  const panelH = stage.offsetHeight;
  const arc = panelH * 0.15;

  (function mv(now) {
    const t = Math.min((now - startT) / dur, 1);
    const x = sx + (tx - sx) * t;
    const y = (sy + (ty - sy) * t) - Math.sin(t * Math.PI) * arc;
    ball.style.left = x + 'px';
    ball.style.top = y + 'px';

    if (t < 1) {
      requestAnimationFrame(mv);
    } else {
      ball.remove();
      spawnExplosion(tx, ty, false);
      spawnSmoke(tx, ty);
      sndExplode(false);

      // 빨강 플래시 (기존 그대로 유지)
      const df = document.getElementById('dmgFlash');
      if (df) {
        df.style.background = 'rgba(231,76,60,.28)';
        df.style.opacity = '1';
        setTimeout(() => df.style.opacity = '0', 380);
      }
    }
  })(performance.now());
}

