const STORIES=[
{icon:'⚔️',title:'조선 건국 3대 드라마',preview:'태조·정종·태종이 피로 만든 조선의 기틀',content:`<div class="story-para"><span class="s-king">태조 이성계</span>는 <span class="s-event">위화도 회군(1388)</span>으로 고려를 장악한 뒤 1392년 <span class="s-event">조선을 건국</span>했다. 책사 <span class="s-king">정도전</span>이 한양을 설계하고 법전의 기초를 잡았다. <span class="s-tip">건국=태조+정도전+한양+위화도</span></div><div class="story-para">아들들이 왕위를 놓고 다퉜다. <span class="s-event">1·2차 왕자의 난</span>으로 이방원이 정적을 제거. <span class="s-king">정종</span>은 잠깐 왕이었을 뿐이다. <span class="s-tip">왕자의 난=정종 때, 주인공은 이방원</span></div><div class="story-para"><span class="s-king">태종</span>은 장인 가문도 숙청하는 냉정함으로 왕권을 굳혔다. <span class="s-event">6조직계제</span>와 <span class="s-event">호패법</span>으로 나라를 장악, 후계자 세종에게 깨끗한 왕권을 물려줬다. <span class="s-tip">태종=왕권강화의 완성자</span></div>`},
{icon:'👑',title:'세종~성종: 조선의 황금기',preview:'훈민정음부터 경국대전까지',content:`<div class="story-para"><span class="s-king">세종</span>은 <span class="s-event">집현전</span>을 세우고 <span class="s-event">훈민정음(1443)</span>을 창제했다. 4군 6진으로 북방을 개척하고 칠정산·측우기 등 과학을 발전시켰다. <span class="s-tip">세종=훈민정음+집현전+4군6진</span></div><div class="story-para"><span class="s-king">세조</span>는 조카 <span class="s-king">단종</span>을 <span class="s-event">계유정난</span>으로 폐위했다. 복위를 꾀하다 처형된 이들이 <span class="s-event">사육신</span>, 은거한 이들이 <span class="s-event">생육신</span>. <span class="s-tip">계유정난→단종 폐위→사육신·생육신</span></div><div class="story-para"><span class="s-king">성종</span>은 <span class="s-event">경국대전(1485)</span>을 완성·반포하고 <span class="s-event">홍문관</span>을 설치했다. 사림을 등용해 조선의 황금기를 완성했다. <span class="s-tip">성종=경국대전+홍문관+사림 등용</span></div>`},
{icon:'🔥',title:'4대 사화: 훈구 vs 사림',preview:'무오·갑자·기묘·을사를 한 번에',content:`<div class="story-para">훈구파(공신 집안)와 사림파(지방 선비)의 충돌로 <span class="s-event">4대 사화</span>가 일어났다.</div><div class="story-para"><span class="s-event">무오(1498)</span> — <span class="s-king">연산군</span>. 사초 문제. <span class="s-tip">무오=연산군+사초</span></div><div class="story-para"><span class="s-event">갑자(1504)</span> — 역시 <span class="s-king">연산군</span>. 폐비 윤씨 복수. <span class="s-tip">갑자=연산군+폐비 윤씨</span></div><div class="story-para"><span class="s-event">기묘(1519)</span> — <span class="s-king">중종</span>. <span class="s-king">조광조</span>가 급진 개혁 후 훈구파 반발로 제거. <span class="s-tip">기묘=중종+조광조</span></div><div class="story-para"><span class="s-event">을사(1545)</span> — <span class="s-king">명종</span>. 대윤(윤임) vs 소윤(윤원형), 문정왕후가 소윤 편. <span class="s-tip">을사=명종+대윤vs소윤</span></div>`},
{icon:'⛵',title:'임진왜란·정묘·병자호란',preview:'선조~인조, 전쟁의 시대',content:`<div class="story-para"><span class="s-king">선조</span> 때 <span class="s-event">임진왜란(1592)</span>. <span class="s-king">이순신</span>이 거북선으로 활약. 의병·명 원군 참전. <span class="s-tip">임진왜란=선조+이순신+거북선</span></div><div class="story-para"><span class="s-king">광해군</span>은 <span class="s-event">중립 외교</span>(명·후금 사이). 서인이 반발, <span class="s-event">인조반정(1623)</span>으로 폐위. <span class="s-tip">광해군=중립외교→인조반정</span></div><div class="story-para"><span class="s-king">인조</span>의 친명배금으로 <span class="s-event">정묘호란(1627)</span>=형제 관계. <span class="s-event">병자호란(1636)</span>=<span class="s-event">삼전도</span>에서 군신 관계 굴욕. <span class="s-tip">정묘=형제 / 병자=군신+삼전도</span></div>`},
{icon:'🏛️',title:'영조·정조: 탕평의 시대',preview:'붕당을 넘어 개혁을 꿈꾼 두 왕',content:`<div class="story-para"><span class="s-king">영조</span>는 <span class="s-event">탕평책</span>으로 붕당 완화, <span class="s-event">균역법</span>으로 군포 반감. 아들 <span class="s-king">사도세자</span>를 뒤주에 가두어 죽인 비극. <span class="s-tip">영조=탕평+균역법+사도세자</span></div><div class="story-para"><span class="s-king">정조</span>는 <span class="s-event">규장각</span>·<span class="s-event">초계문신제</span>·<span class="s-event">수원화성</span> 건설. <span class="s-event">신해통공</span>으로 상업 발전. <span class="s-tip">정조=규장각+수원화성+신해통공</span></div><div class="story-para">정조 사후 <span class="s-king">순조</span> 때 안동 김씨가 권력 독점, <span class="s-event">세도정치</span> 시작. 헌종→철종까지 60년 지속. <span class="s-tip">세도=순조→헌종→철종 (3대 60년)</span></div>`},
{icon:'🌏',title:'고종·순종: 제국의 황혼',preview:'대한제국 선포부터 경술국치까지',content:`<div class="story-para"><span class="s-king">고종</span> 즉위 후 <span class="s-king">흥선대원군</span>이 서원 철폐·경복궁 중건·쇄국. 1876년 <span class="s-event">강화도조약</span>으로 문호 개방. <span class="s-tip">흥선대원군→강화도조약</span></div><div class="story-para"><span class="s-event">갑신정변(1884)</span>→<span class="s-event">동학농민운동(1894)</span>→<span class="s-event">갑오개혁</span>→<span class="s-event">을미사변</span>(명성황후 시해)→<span class="s-event">아관파천</span>. <span class="s-tip">갑신→동학→갑오→을미→아관</span></div><div class="story-para">1897년 <span class="s-event">대한제국</span> 선포. 1905년 을사조약 → 1907년 헤이그 특사 후 강제 퇴위 → <span class="s-king">순종</span> 즉위 → 1910년 <span class="s-event">경술국치</span>로 조선 멸망. <span class="s-tip">대한제국→을사조약→헤이그→경술국치</span></div>`},
];
