let BS={qs:[],idx:0,score:0,combo:0,wrong:[],hp:3,isFinalBlow:false,_autoTimer:null,_countInterval:null,_gameOver:false};
let _eHp=100;
function getEHp(){return _eHp;}
function setEHp(v){_eHp=v;const f=document.getElementById('enemyHpFill');if(f)f.style.width=v+'%';}
let flippedCards=new Set();

/* ══════════════════════════════════════
   SCREENS
══════════════════════════════════════ */
function showScreen(id){
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  sndClick();
  if(id==='cards')renderCards('all');
  if(id==='timeline')renderTimeline();
  if(id==='story')renderStoryList();
}

/* ══════════════════════════════════════
   CARDS
══════════════════════════════════════ */
const ERA_ORDER=['전기','중기','중후기','후기','말기','근대'];
function renderCards(era){
  const c=document.getElementById('cardsContainer');c.innerHTML='';
  const eras=era==='all'?ERA_ORDER:[era];
  eras.forEach(e=>{
    const kings=KINGS.filter(k=>k.era===e);if(!kings.length)return;
    const cfg=ERA_CONFIG[e];
    const eraCss={'전기':'early','중기':'mid','중후기':'midlate','후기':'late','말기':'end','근대':'empire'}[e];
    const sec=document.createElement('div');sec.className='era-section';
    sec.innerHTML=`<div class="era-section-header"><span class="era-section-badge ${cfg.badge}">${e}</span><div class="era-section-line" style="background:${cfg.line}"></div></div><div class="era-desc" style="border-color:${cfg.color};color:${cfg.color};">${cfg.desc}</div><div class="cards-grid">${kings.map(k=>`
      <div class="flip-card${flippedCards.has(k.id)?' flipped':''}" onclick="flipCard(this,${k.id})">
        <div class="flip-inner">
          <div class="flip-front era-${eraCss}${k.imp?' imp':''}">
            <div class="card-era-dot" style="background:${cfg.color};box-shadow:0 0 8px ${cfg.color}66;"></div>
            <span class="card-num">${k.id}대</span>
            <span class="card-name">${k.name}</span>
            <span class="card-years">${k.years}</span>
            <span class="card-hint">▾ 클릭</span>
          </div>
          <div class="flip-back era-${eraCss}${k.imp?' imp-back':''}">
            <div class="back-name">
              <span>${k.name}</span>
              <span class="back-years">${k.years}</span>
            </div>
            <div class="back-nick">${k.nick||''}</div>
            <div class="back-divider"></div>
            <div class="mini-tags">${k.tags.map((t,i)=>`<span class="mini-tag mt-${t.c}${t.c==='r'?' mt-key':''}">${t.t}</span>`).join('')}</div>
          </div>
        </div>
      </div>`).join('')}</div>`;
    c.appendChild(sec);
  });
}
function flipCard(el,id){
  // 카드 도감에서 카드를 넘길 때 전용 플립 효과음
  try{ sndCardFlip(); }catch(e){}
  el.classList.toggle('flipped');
  if(flippedCards.has(id)){
    flippedCards.delete(id);
    el.style.height='';
  } else {
    flippedCards.add(id);
    // 높이 변경 없이 overflow로 처리 - 레이아웃 밀림 방지
  }
}
function filterEra(era,tab){
  try{ sndClick(); }catch(e){}
  document.querySelectorAll('.era-tab').forEach(t=>t.classList.remove('active'));
  tab.classList.add('active');
  renderCards(era);
}

/* ══════════════════════════════════════
   BATTLE
══════════════════════════════════════ */
function shuffle(a){let r=[...a];for(let i=r.length-1;i>0;i--){let j=~~(Math.random()*(i+1));[r[i],r[j]]=[r[j],r[i]];}return r;}
function noConsecKing(qs){const arr=[...qs];for(let i=1;i<arr.length;i++){if(arr[i].king&&arr[i-1].king&&arr[i].king.id===arr[i-1].king.id){for(let j=i+1;j<arr.length;j++){if(!arr[j].king||arr[j].king.id!==arr[i-1].king.id){[arr[i],arr[j]]=[arr[j],arr[i]];break;}}}}return arr;}

function startBattle(pool,count=10){
  let pool2=[...QUIZ_POOL];

  if(BS._autoTimer)clearTimeout(BS._autoTimer);
  if(BS._countInterval)clearInterval(BS._countInterval);
  BS={qs:noConsecKing(shuffle(pool2)).slice(0,Math.min(count,pool2.length)),idx:0,score:0,combo:0,wrong:[],hp:3,isFinalBlow:false,_autoTimer:null,_countInterval:null,_gameOver:false};
  _eHp=100;setEHp(100);
  showScreen('battle');
  setTimeout(()=>{resizeFx();renderBQ();},60);
}


function renderBQ(){
  const q=BS.qs[BS.idx];if(!q){showResult();return;}
  // HUD
  document.getElementById('hudNum').textContent=`${BS.idx+1}/${BS.qs.length}`;
  document.getElementById('hudBar').style.width=((BS.idx/BS.qs.length)*100)+'%';
  document.getElementById('hudScore').textContent=BS.score+'점';
  const ce=document.getElementById('hudCombo');
  ce.textContent=`콤보 ${BS.combo}🔥`;ce.className='hud-combo'+(BS.combo>=3?' fire':'');
  updateHearts();
  // Question box
  document.getElementById('qBadge').textContent='◆ 조선왕조 퀴즈';
  const kwEl=document.getElementById('qKeyword');
  kwEl.textContent=q.keyword||'';
  kwEl.style.fontSize=q.keyword&&q.keyword.length>30?'clamp(13px,2.8vw,18px)':'clamp(15px,3.2vw,24px)';
  const kwBot=document.getElementById('qKeywordBottom');
  if(kwBot)kwBot.textContent='';
  document.getElementById('qKingEra').textContent='';
  document.getElementById('qText').textContent=q.question;
  document.getElementById('qHint').textContent='';
  document.getElementById('qHint').classList.remove('show');
  const exEl=document.getElementById('qExplain');
  if(exEl){exEl.className='q-explain';exEl.innerHTML='';}
  document.getElementById('nextBtn').style.display='none';
  // Choices
  const hand=document.getElementById('handArea');hand.innerHTML='';
  shuffle(q.choices).forEach((c,i)=>{
    const btn=document.createElement('button');btn.className='hand-card';
    btn.innerHTML=`<span class="hand-sub">▶ ${i+1}번</span>${c}`;
    btn.onclick=()=>selectAnswer(c,btn,q);hand.appendChild(btn);
  });
  updateComboBadge();BS.isFinalBlow=false;
}

function showHint(){document.getElementById('qHint').classList.add('show');sndClick();}
function updateHearts(){['hrt1','hrt2','hrt3'].forEach((id,i)=>{document.getElementById(id).classList.toggle('lost',i>=BS.hp);});}
function updateComboBadge(){
  const el=document.getElementById('comboBadge');const c=BS.combo;el.classList.remove('show');if(!c)return;
  if(c>=15){el.textContent='🌊 학익진 대포격!!!';el.style.color='var(--gold3)';}
  else if(c>=10){el.textContent='🐢 거북선 포격!';el.style.color='#ff9500';}
  else if(c>=5){el.textContent='⚓ 연속 포격!!';el.style.color='#f0c040';}
  else{el.textContent=`🔥 ${c}연속 정답!`;el.style.color='rgba(240,192,64,.8)';}
  el.classList.add('show');
}

/* ══════════════════════════════════════
   ANSWER PICK
══════════════════════════════════════ */
function selectAnswer(chosen,btn,q){
  if(BS.isFinalBlow||document.querySelectorAll('.hand-card:disabled').length>0)return;
  document.querySelectorAll('.hand-card').forEach(b=>b.disabled=true);
  const correct=chosen===q.answer,isLast=(BS.idx===BS.qs.length-1);

if(correct){
    btn.classList.add('correct-card');
    BS.combo++;
    const bonus=BS.combo>=3?30:20;
    BS.score+=bonus;
    sndCorrect();sndCombo(BS.combo);
    updateComboBadge();showStamp(true);

    // ★★★ 맞았을 때도 오답과 똑같이 dmgFlash만 사용 ★★★
    // questionBox 초록 플래시 완전 제거
    const qbox = document.getElementById('questionBox');
    qbox.classList.remove('correct-flash');

    if(isLast){BS.isFinalBlow=true;doFinalBlow();}
    else{
      doPlayerAttack();
      // 2초 후 자동 이동
      BS._autoTimer=setTimeout(()=>{BS.idx++;renderBQ();},2000);
    }
  } else {
    btn.classList.add('wrong-card');
    document.querySelectorAll('.hand-card').forEach(b=>{
      if(b.textContent.includes(q.answer))b.classList.add('correct-card');
    });
    BS.combo=0;BS.hp=Math.max(0,BS.hp-1);
    sndWrong();sndEnemyAtk();
    updateHearts();showStamp(false);
    doEnemyAttack();
    // 틀렸을 때: 해설 슬라이드 + 버튼
    showWrongExplain(q);
    if(BS.hp<=0){ BS._gameOver=true; }
  }
}

function showWrongExplain(q){
  // 질문 박스 안 q-explain 영역에 해설 슬라이드 등장
  const el=document.getElementById('qExplain');
  const mhho=MHHO[q.answer];
  const mhhoHtml=mhho?`<div class="q-mhho-wrap">
    <div class="q-mhho-toggle" onclick="this.closest('.q-mhho-wrap').classList.toggle('open')">👑 묘호 이야기&nbsp;&nbsp;▼</div>
    <div class="q-mhho-body">
      <div class="q-mhho-title">${mhho.title}</div>
      <div class="q-mhho-text">${mhho.text}</div>
      <div class="q-mhho-source">${mhho.source}</div>
    </div>
  </div>`:'';
  el.innerHTML=`<div class="q-explain-inner">
    <div class="q-explain-answer">💀 빗나감 — 정답: ${q.answer}</div>
    <div class="q-explain-label">[정답 해설]</div>
    <div class="q-explain-text">${q.explain}</div>
    ${mhhoHtml}
  </div>`;
  el.className='q-explain show';
  // 다음 문제 버튼 표시
  const nb=document.getElementById('nextBtn');
  nb.style.display='block';
  nb.textContent='다음 문제 →';
}

/* ══════════════════════════════════════
   ATTACK ANIMATIONS
══════════════════════════════════════ */
function doPlayerAttack(){
  const panel=document.getElementById('battleBgPanel');
  const W=panel.offsetWidth,H=panel.offsetHeight;
  const sx=W*.09,sy=H*.58,tx=W*.72,ty=H*.44;
  const c=BS.combo;

  if(c>=15){
    // 학익진 대포격: 과할 정도로 퍼붓기
    showSpecial('🌊 학익진 대포격!!!','radial-gradient(ellipse at center,rgba(255,200,0,.35) 0%,transparent 70%)','var(--gold3)');
    // 1파: 즉시 4발
    for(let i=0;i<4;i++) setTimeout(()=>launchCannonball(sx,sy,tx+(Math.random()-.5)*90,ty+(Math.random()-.5)*45,true),i*55);
    // 2파: 200ms 뒤 4발
    for(let i=0;i<4;i++) setTimeout(()=>launchCannonball(sx,sy,tx+(Math.random()-.5)*90,ty+(Math.random()-.5)*45,true),200+i*55);
    // 3파: 450ms 뒤 4발
    for(let i=0;i<4;i++) setTimeout(()=>launchCannonball(sx,sy,tx+(Math.random()-.5)*90,ty+(Math.random()-.5)*45,true),450+i*55);
    // 화면 2번 연속 흔들기 (포탄 충돌 타이밍에 맞춰 조정)
    setTimeout(()=>triggerShake(panel,'correct-attack'),950);
    setTimeout(()=>triggerShake(panel,'correct-attack'),1400);
    setEHp(Math.max(0,getEHp()-30));

  } else if(c>=10){
    // 거북선 포격: 0.2초 충전 후 강력한 1발
    showSpecial('🐢 거북선 포격!','radial-gradient(ellipse at center,rgba(255,107,53,.28) 0%,transparent 70%)','#ff9500');
    // 충전 효과: 포구에 빛이 모이는 연출
    const charge=document.createElement('div');
    charge.style.cssText=`position:absolute;left:${sx-24}px;top:${sy-24}px;width:48px;height:48px;border-radius:50%;background:radial-gradient(circle,rgba(255,200,0,.9),rgba(255,100,0,.6),transparent);pointer-events:none;z-index:15;transition:all .18s ease-in;transform:scale(0.2);opacity:0;`;
    panel.appendChild(charge);
    setTimeout(()=>{charge.style.transform='scale(1.2)';charge.style.opacity='1';},20);
    // 0.2초 뒤 충전 완료 후 강력 발사
    setTimeout(()=>{
      charge.style.transform='scale(2.5)';charge.style.opacity='0';
      setTimeout(()=>charge.remove(),200);
      launchCannonball(sx,sy,tx+(Math.random()-.5)*20,ty+(Math.random()-.5)*15,true);
      spawnCannonSmoke(sx,sy);spawnCannonSmoke(sx,sy);
      // 충전 후 발사된 포탄이 맞는 시점(약 0.22s + 0.95s)에 맞춰 흔들림
      setTimeout(()=>triggerShake(panel,'correct-attack'),1170);
    },220);
    setEHp(Math.max(0,getEHp()-20));

  } else if(c>=5){
    // 연속 포격: 2발 연속
    showSpecial('⚓ 연속 포격!!','radial-gradient(ellipse at center,rgba(212,150,26,.22) 0%,transparent 70%)','#f0c040');
    for(let i=0;i<2;i++) setTimeout(()=>launchCannonball(sx,sy,tx+(Math.random()-.5)*50,ty+(Math.random()-.5)*25,false),i*200);
    // 두 번째 포탄이 맞는 시점(0.2s + 0.95s)에 맞춰 흔들림
    setTimeout(()=>triggerShake(panel,'correct-attack'),1150);
    setEHp(Math.max(0,getEHp()-15));

  } else {
    // 기본 단발
    launchCannonball(sx,sy,tx+(Math.random()-.5)*30,ty+(Math.random()-.5)*20,false);
    // 단발 포탄이 맞는 시점(비행 시간 0.95s)에 맞춰 흔들림/테두리 효과
    setTimeout(()=>triggerShake(panel,'correct-attack'),950);
    setEHp(Math.max(0,getEHp()-5));
  }
}

function doEnemyAttack(){
  const panel=document.getElementById('battleBgPanel');
  const W=panel.offsetWidth,H=panel.offsetHeight;
  const sx=W*.63,sy=H*.38,tx=W*.17,ty=H*.55;

  // 오답(피격)도 launchCannonball의 dmgFlash 로직과 100% 동일하게 사용
  launchCannonball(sx,sy,tx,ty,false,true);

  // 화면 흔들림은 기존과 동일하게 비행 시간 후에만 처리
  setTimeout(()=>{
    triggerShake(panel,'enemy-attack');
  },950);
}


function doFinalBlow(){
  const panel=document.getElementById('battleBgPanel');
  const W=panel.offsetWidth,H=panel.offsetHeight;
  const sx=W*.09,sy=H*.58,tx=W*.72,ty=H*.44;
  // dragon flash
  const fl=document.createElement('div');
  fl.style.cssText=`position:absolute;left:${sx-36}px;top:${sy-36}px;width:72px;height:72px;border-radius:50%;background:radial-gradient(circle,rgba(255,220,0,.95),rgba(255,100,0,.6),transparent);pointer-events:none;z-index:15;transition:opacity .15s;`;
  panel.appendChild(fl);setTimeout(()=>{fl.style.opacity='0';setTimeout(()=>fl.remove(),200);},280);
  spawnCannonSmoke(sx,sy);sndCannon();
  const fbo=document.getElementById('finalBlowOverlay'),fbt=document.getElementById('finalBlowText');
  fbo.style.opacity='1';fbt.style.opacity='1';
  setTimeout(()=>{for(let i=0;i<4;i++)setTimeout(()=>launchCannonball(sx,sy,tx+(Math.random()-.5)*40,ty+(Math.random()-.5)*20,true),i*90);},200);
  setTimeout(()=>{for(let i=0;i<4;i++)setTimeout(()=>launchCannonball(sx,sy,tx+(Math.random()-.5)*50,ty+(Math.random()-.5)*28,true),i*75);},700);
  setTimeout(()=>{
    spawnExplosion(tx,ty,true);spawnExplosion(tx-38,ty-18,true);spawnExplosion(tx+38,ty+18,true);
    spawnSmoke(tx,ty,20);triggerShake(panel,'correct-attack');setEHp(0);
  },1300);
  setTimeout(()=>{fbo.style.opacity='0';fbt.style.opacity='0';showResult();sndVictory();},3200);
}

function triggerShake(el,cls){el.classList.remove(cls);void el.offsetWidth;el.classList.add(cls);setTimeout(()=>el.classList.remove(cls),700);}
function showSpecial(txt,bg,col){
  const ov=document.getElementById('specialOverlay'),bel=document.getElementById('specialBg'),tel=document.getElementById('specialTxt');
  bel.style.background=bg;tel.textContent=txt;tel.style.color=col||'var(--gold3)';
  ov.style.opacity='1';setTimeout(()=>ov.style.opacity='0',1100);
}
function showDmgFloat(x,y,txt,isPlayer){
  const d=document.createElement('div');d.className='dmg-float '+(isPlayer?'hit':'enemy-hit');d.textContent=txt;
  const panel=document.getElementById('battleBgPanel');const r=panel.getBoundingClientRect();
  d.style.left=(r.left+x-20)+'px';d.style.top=(r.top+y-10)+'px';d.style.position='fixed';
  document.getElementById('dmgContainer').appendChild(d);setTimeout(()=>d.remove(),950);
}
function showStamp(_correct){}
function nextQuestion(){
  if(BS._autoTimer){clearTimeout(BS._autoTimer);BS._autoTimer=null;}
  if(BS._countInterval){clearInterval(BS._countInterval);BS._countInterval=null;}
  if(BS._gameOver){showResult();return;}
  BS.idx++;
  if(BS.idx>=BS.qs.length||BS.hp<=0)showResult();else renderBQ();
}

/* ══════════════════════════════════════
   RESULT
══════════════════════════════════════ */
function showResult(){
  showScreen('result');_eHp=100;setEHp(100);
  const s=BS.score;let emoji,title,grade;
  if(s>=270){emoji='👑';title='영의정 수준!';grade='27왕을 모두 격파할 실력이다';}
  else if(s>=200){emoji='🎖️';title='당상관 합격!';grade='한국사 시험 무난히 통과할 실력';}
  else if(s>=120){emoji='📚';title='조금 더 공부를!';grade='스토리 모드로 복습해봐라';}
  else{emoji='😅';title='처음부터 다시!';grade='카드 도감 → 스토리 → 배틀 순서로 공략하라';}
  document.getElementById('resultEmoji').textContent=emoji;
  document.getElementById('resultTitle').textContent=title;
  document.getElementById('resultScore').innerHTML=`<span>${s}</span>점`;
  document.getElementById('resultGrade').textContent=grade;
  launchFireworks();
}
function launchFireworks(){
  for(let f=0;f<7;f++)setTimeout(()=>{
    const x=Math.random()*innerWidth,y=Math.random()*innerHeight*.65;
    const cols=['#d4a017','#f0c040','#e74c3c','#2ecc71','#3498db','#ff9500','#ff6b35'];
    for(let s=0;s<22;s++){
      const sp=document.createElement('div');sp.className='fw-spark';
      const a=(s/22)*Math.PI*2,d=75+Math.random()*75;
      sp.style.cssText=`left:${x}px;top:${y}px;width:7px;height:7px;background:${cols[~~(Math.random()*cols.length)]};--tx:${Math.cos(a)*d}px;--ty:${Math.sin(a)*d}px;--d:${.7+Math.random()*.5}s;`;
      document.body.appendChild(sp);setTimeout(()=>sp.remove(),1400);
    }
  },f*360);
}

/* ══════════════════════════════════════
   TIMELINE
══════════════════════════════════════ */
function renderTimeline(){
  const wrap=document.getElementById('timelineWrap');
  [...wrap.querySelectorAll('.tl-item,.tl-era-divider')].forEach(e=>e.remove());
  let lastEra='';
  KINGS.forEach((k,i)=>{
    if(k.era!==lastEra){
      const cfg=ERA_CONFIG[k.era];
      const div=document.createElement('div');div.className='tl-era-divider';div.style.animationDelay=(i*.04)+'s';
      div.innerHTML=`<span class="tl-era-divider-badge ${cfg.badge}" onclick="try{sndClick();}catch(e){}">${k.era}</span><div class="tl-era-divider-line" style="background:${cfg.color}"></div><span style="font-size:9px;color:${cfg.color};white-space:nowrap;">${cfg.desc.split('|')[0].trim()}</span>`;
      wrap.appendChild(div);lastEra=k.era;
    }
    const item=document.createElement('div');item.className='tl-item';item.style.animationDelay=(i*.04)+'s';
    item.innerHTML=`<div class="tl-num-wrap"><span class="tl-num">${k.id}대</span><div class="tl-dot${k.imp?' imp':''}"></div></div>
      <div class="tl-card${k.imp?' imp-tl':''}" onclick="try{sndClick();}catch(e){} this.querySelector('.tl-tags').style.display=this.querySelector('.tl-tags').style.display==='none'?'flex':'none'">
        <div class="tl-name">${k.name} <span style="font-size:9px;color:#7f8c8d;font-family:'Noto Sans KR'">${k.years}</span></div>
        <div class="tl-tags" style="display:none">${k.tags.map(t=>`<span class="mini-tag mt-${t.c}">${t.t}</span>`).join('')}</div>
      </div>`;
    wrap.appendChild(item);
  });
  const endDiv=document.createElement('div');endDiv.className='tl-era-divider';
  endDiv.innerHTML=`<span class="tl-era-divider-badge era-badge-empire" style="background:rgba(100,0,0,.3);color:#ff4444;border-color:rgba(180,0,0,.5);">━━ 경술국치 1910 ━━ 조선 멸망 ━━ 일제강점기 시작 ━━</span>`;
  wrap.appendChild(endDiv);
}

