function renderStoryList(){
  document.getElementById('storySelectWrap').style.display='block';
  document.getElementById('storyReader').classList.remove('show');
  document.getElementById('storyList').innerHTML=STORIES.map((s,i)=>`
    <div class="story-item" onclick="try{sndClick();}catch(e){} openStory(${i})">
      <div class="story-icon">${s.icon}</div>
      <div style="flex:1"><div class="story-name">${s.title}</div><div class="story-preview">${s.preview}</div></div>
      <div class="story-arrow">→</div>
    </div>`).join('');
}
function openStory(i){
  const s=STORIES[i];
  document.getElementById('storySelectWrap').style.display='none';
  document.getElementById('storyTitleBig').textContent=s.icon+' '+s.title;
  document.getElementById('storyContent').innerHTML=s.content;
  document.getElementById('storyReader').classList.add('show');
}
function closeStory(){
  try{ sndClick(); }catch(e){}
  document.getElementById('storySelectWrap').style.display='block';
  document.getElementById('storyReader').classList.remove('show');
}
function backFromStory(){showScreen('home');}



